        .control_mode = flags.control_mode,
        .terminal_256 = flags.force_256,
    };
    client.connect() catch |err| switch (err) {
        error.ConnectFailed => {
            try autostartServer(alloc, socket_path, flags.config_file);
            try client.connect();
        },
        else => return err,
    };
    defer client.disconnect();

