/// Identification message sent by client on connect.
pub const IdentifyMsg = extern struct {
    protocol_version: u32 align(1),
    pid: i32 align(1),
    flags: IdentifyFlags align(1),
    term_name: [64]u8 align(1),
    tty_name: [64]u8 align(1),
    cols: u16 align(1),
