fn parseArgs(alloc: std.mem.Allocator, init_args: std.process.Args) Flags {
    var flags = Flags{ .remaining = .empty };
    var args = std.process.Args.Iterator.init(init_args);
    _ = args.next();

    while (args.next()) |arg| {
        if (arg.len < 2 or arg[0] != '-') {
