const std = @import("std");

/// Events produced by the input parser.
pub const InputEvent = union(enum) {
    print: u21,
    c0: u8,
    csi: CSI,
    osc: OSC,
    esc: ESC,
    dcs: DCS,
};

pub const CSI = struct {
    final: u8,
    intermediates: [4]u8 = .{ 0, 0, 0, 0 },
    intermediate_count: u3 = 0,
    params: [16]u16 = .{0} ** 16,
    param_count: u5 = 0,

    pub fn getParam(self: *const CSI, index: usize, default: u16) u16 {
        if (index >= self.param_count) return default;
        const val = self.params[index];
        return if (val == 0) default else val;
    }
};

pub const OSC = struct {
    ps: u16,
    data: [8192]u8 = .{0} ** 8192,
    data_len: u16 = 0,

    pub fn getData(self: *const OSC) []const u8 {
        return self.data[0..self.data_len];
    }
};

pub const ESC = struct {
    final: u8,
    intermediate: u8 = 0,
};

pub const DCS = struct {
    final: u8,
    intermediates: [4]u8 = .{ 0, 0, 0, 0 },
    intermediate_count: u3 = 0,
    params: [16]u16 = .{0} ** 16,
    param_count: u5 = 0,
    data: [4096]u8 = .{0} ** 4096,
    data_len: u16 = 0,

    pub fn getData(self: *const DCS) []const u8 {
        return self.data[0..self.data_len];
    }
};

pub const State = enum {
    ground,
    escape,
    escape_intermediate,
    csi_entry,
    csi_param,
    csi_intermediate,
    csi_ignore,
    osc_string,
    osc_escape,
    dcs_entry,
    dcs_param,
    dcs_intermediate,
    dcs_passthrough,
    dcs_escape,
    dcs_ignore,
};

/// VT100/xterm escape sequence parser.
pub const Parser = struct {
    state: State = .ground,
    params: [16]u16 = .{0} ** 16,
    param_count: u5 = 0,
