fn drainFdForTest(fd: std.c.fd_t) void {
    var buf: [4096]u8 = undefined;
    while (true) {
        const n = std.c.read(fd, &buf, buf.len);
        if (n > 0) continue;
        if (n < 0 and std.posix.errno(n) == .AGAIN) break;
        break;
    }
}

