fn sleepMs(ms: u64) void {
    var ts = std.c.timespec{
        .sec = @intCast(ms / 1000),
        .nsec = @intCast((ms % 1000) * std.time.ns_per_ms),
    };
    _ = std.c.nanosleep(&ts, null);
}

fn setFdNonblocking(fd: std.c.fd_t) void {
    const flags = std.c.fcntl(fd, std.c.F.GETFL);
